import React, { useState, useEffect } from 'react';
import Icon from '../../components/common/Icon';
import { icons } from '../../config/icons';
import { usePopupMenu } from '../../context/PopupMenuContext';
import { Link } from 'react-router-dom';
import { useHeaderTab } from '../../context/HeaderTabContext';

const Pagelet = () => {
    const { openPopupMenu, closePopupMenu } = usePopupMenu();
    const renderRowActions = () => {
        return (
            <div className='popup-menu-content'>
                <button onClick={() => { closePopupMenu(); }}><Icon icon={icons.import} />Import</button>
                <button onClick={() => { closePopupMenu(); }}><Icon icon={icons.export} />Export</button>
                <button onClick={() => { closePopupMenu(); }}><Icon icon={icons.print} />Print</button>
            </div>
        );
    };

    const [activeTab, setActiveTab] = useState(1);
    const tabContent = {
        1: <p className="p"><b>Tab 1</b> - Lorem Ipsum has been the industry's standard dummy text ever since the 1500s, when an unknown printer took a galley.</p>,
        2: <p className="p"><b>Tab 2</b> - Lorem Ipsum has been the industry's standard dummy text ever since the 1500s, when an unknown printer took a galley.</p>,
        3: <p className="p"><b>Tab 3</b> - Lorem Ipsum has been the industry's standard dummy text ever since the 1500s, when an unknown printer took a galley.</p>,
    };

    /* Sample Header Tab */
    const [showHeaderTabs, setShowHeaderTabs] = useState(false);
    //const [activeHeaderTab, setActiveHeaderTab] = useState(1);
    const { displayHeaderTabs, clearHeaderTabs } = useHeaderTab();

    useEffect(() => {
        const headerTabs = {
            label: 'Page:', // The label to show next to the tabs
            tabs: [
                { label: 'Tab 1', isActive: activeTab === 1, onClick: () => setActiveTab(1) },
                { label: 'Tab 2', isActive: activeTab === 2, onClick: () => setActiveTab(2) },
                { label: 'Tab 3', isActive: activeTab === 3, onClick: () => setActiveTab(3) },     // setActiveHeaderTab(3)
            ]
        };

        if (showHeaderTabs) { displayHeaderTabs(headerTabs); }
        else { clearHeaderTabs(); }
    }, [showHeaderTabs, activeTab, displayHeaderTabs, clearHeaderTabs]);

    useEffect(() => { return () => { clearHeaderTabs(); }; }, [clearHeaderTabs]);
    /* Sample Header Tab end */

    return (
        <div className='admin-pager'>
            <header className='admin-pager-head'>
                <div className='admin-pager-title'> <span><h2>Pagelet Templates</h2><p>Multiple Pagelet designs</p></span>  </div>
            </header>

            <div className='admin-pager-body'>
                <div className='flex-column'>
                    <div className='w5'>
                        <div className='pagelet'>
                            <div className='pagelet-head'>
                                <Icon icon={icons.shop} className='pagelet-head-icon' />
                                <h4>ICON HEADER</h4>
                                <div className='pagelet-head-btn'> <button className='button icon btn-link' onClick={(e) => openPopupMenu({ referenceElement: e.currentTarget, content: renderRowActions(), placement: 'left-start', })} > <Icon icon={icons.ellipsisV} /> </button> </div>
                            </div>
                            <div className='pagelet-in'> <p className='p'>Lorem Ipsum has been the industry's standard dummy text ever since the 1500s, when an unknown printer took a galley of type and scrambled.</p> </div>
                            <div className='pagelet-foot'>
                                <button className='button btn-secondary'><Icon icon={icons.error} /> Cancel</button>
                                <button type='submit' className='button'><Icon icon={icons.send} />Submit</button>
                            </div>
                        </div>
                    </div>
                    <div className='w5'>
                        <div className='pagelet'>
                            <div className='pagelet-head'>
                                <h4><Icon icon={icons.shop} className='pagelet-head-icon' />ICON HEADER</h4>
                                <div className='pagelet-head-btn'> <button className='button btn-link' onClick={(e) => openPopupMenu({ referenceElement: e.currentTarget, content: renderRowActions(), placement: 'left-start', })} > Actions </button> </div>
                            </div>
                            <div className='pagelet-in'> <p className='p'>Lorem Ipsum has been the industry's standard dummy text ever since the 1500s, when an unknown printer took a galley of type and scrambled.</p> </div>
                            <div className='pagelet-foot'>
                                <button className='button btn-outlined'>Cancel</button>
                                <button type='submit' className='button btn-success'>Submit</button>
                            </div>
                        </div>
                    </div>
                </div>

                <div className='flex-column'>
                    <div className='w5'>
                        <div className='pagelet'>
                            <div className='tab-case bordered'>
                                <ul> {[1, 2, 3].map((tab) => (<li key={tab} > <Link className={`nav-link ${activeTab === tab ? 'active' : ''}`} to="#" onClick={(e) => { e.preventDefault(); setActiveTab(tab); }} > Tab {tab} </Link> </li>))} </ul>
                            </div>
                            <div className='pagelet-in'> {tabContent[activeTab]} </div>
                            <div className='pagelet-foot'>
                                <button className='button btn-outlined'>Cancel</button>
                                <button type='submit' className='button'>Submit</button>
                            </div>
                        </div>
                    </div>
                    <div className='w5'>
                        <div className='pagelet'>
                            <div className='pagelet-head tab-case bordered right'>
                                <h4><Icon icon={icons.shop} className='pagelet-head-icon' />ICON HEADER</h4>
                                <ul> {[1, 2, 3].map((tab) => (<li key={tab} > <Link className={`nav-link ${activeTab === tab ? 'active' : ''}`} to="#" onClick={(e) => { e.preventDefault(); setActiveTab(tab); }} > Tab {tab} </Link> </li>))} </ul>
                            </div>
                            <div className='pagelet-in'> {tabContent[activeTab]} </div>
                            <div className='pagelet-foot'>
                                <button className='button btn-danger'>No</button>
                                <button type='submit' className='button btn-warning'>Yes</button>
                            </div>
                        </div>
                    </div>
                </div>

                <div className='flex-column'>
                    <div className='w5'>
                        <div className='pagelet'>
                            <div className='tab-case bordered full'>
                                <ul> {[1, 2, 3].map((tab) => (<li key={tab} > <Link className={`nav-link ${activeTab === tab ? 'active' : ''}`} to="#" onClick={(e) => { e.preventDefault(); setActiveTab(tab); }} > Tab {tab} </Link> </li>))} </ul>
                            </div>
                            <div className='pagelet-in'> {tabContent[activeTab]} </div>
                            <div className='pagelet-foot'> <button className='button' onClick={() => setShowHeaderTabs(prev => !prev)}> {showHeaderTabs ? 'Header Tabs' : 'Title Tabs'} </button> </div>
                        </div>
                    </div>
                    <div className='w5'>
                        <div className='pagelet'>
                            <div className='pagelet-head tab-case bordered right'>
                                <h4><Icon icon={icons.shop} className='pagelet-head-icon' />HEADER TABS</h4>
                            </div>
                            <div className='pagelet-in'> {tabContent[activeTab]} </div>
                            <div className='pagelet-foot'> <button className={`button ${showHeaderTabs ? 'btn-warning' : 'btn-success'}`} onClick={() => setShowHeaderTabs(prev => !prev)}> {showHeaderTabs ? 'Hide' : 'Show'} Header Tabs</button> </div>
                        </div>
                    </div>
                </div>
            </div>
        </div>);
};
export default Pagelet;